for ref in sample_refs:
    ref_num = ref.split('_')[-1]
    if ref_num in num_to_business_id:
        business_id = num_to_business_id[ref_num]
        # Find the business
        business = next((b for b in all_businesses if b['business_id'] == business_id), None)
        if business:
            sample_mappings[ref] = {
                'business_id': business_id,
                'description': business.get('description', '')
