import json
import re
from collections import Counter, defaultdict

# Load data
business_file = locals()['var_functions.query_db:64']
if isinstance(business_file, str) and business_file.endswith('.json'):
    with open(business_file, 'r') as f:
        all_businesses = json.load(f)
else:
    all_businesses = locals()['var_functions.query_db:64']

reviews = locals()['var_functions.query_db:54']
users_2016 = locals()['var_functions.query_db:66']

# Mapping
num_to_business_id = {}
for business in all_businesses:
    num = business['business_id'].split('_')[-1]
    num_to_business_id[num] = business['business_id']

# Extract main category
def get_main_category(description):
    if not description:
        return 'Other'

    desc = description.lower()

    # Pattern for explicit category lists
    match = re.search(r'(range of services in|including|destination for|seeking|offers.*services) ([^.]+)', desc)
    if match:
        text = match.group(2)
        # Split and get first meaningful category
        cats = re.split(r',\s*', text)
        for cat in cats:
            cat = cat.strip()
            cat = re.sub(r'^and\s+', '', cat)
            cat = re.sub(r'[^a-zA-Z\s&/-]', '', cat)
            cat = cat.strip()

            # Standardize common categories
            if 'restaurant' in cat:
                return 'Restaurants'
            elif 'food' in cat and 'seafood' not in cat:
                return 'Food'
            elif 'beauty' in cat or 'spa' in cat or 'salon' in cat:
                return 'Beauty & Spas'
            elif 'fitness' in cat or 'gym' in cat:
                return 'Fitness & Instruction'
            elif 'pet' in cat:
                return 'Pets'
            elif 'automotive' in cat or 'auto' in cat:
                return 'Automotive'
            elif 'medical' in cat or 'doctor' in cat:
                return 'Health & Medical'
            elif len(cat) > 3:
                return cat.title()

    # Check for specific keywords
    if 'vietnamese' in desc:
        return 'Vietnamese Restaurants'
    elif 'pet groomers' in desc:
        return 'Pet Groomers'
    elif 'gun/rifle ranges' in desc:
        return 'Gun/Rifle Ranges'
    elif 'movers' in desc:
        return 'Movers'
    elif 'veterinarians' in desc:
        return 'Veterinarians'

    return 'Other'

# Map businesses to categories
business_category = {}
for business in all_businesses:
    business_id = business['business_id']
    desc = business.get('description', '')
    business_category[business_id] = get_main_category(desc)

# Count reviews by category
category_totals = Counter()
review_counts = Counter()

for review in reviews:
    business_ref = review.get('business_ref', '')
    if business_ref:
        review_counts[business_ref] += 1

# Process
for business_ref, count in review_counts.items():
    ref_num = business_ref.split('_')[-1]

    if ref_num in num_to_business_id:
        business_id = num_to_business_id[ref_num]
        category = business_category[business_id]
        category_totals[category] += count

# Get top 5
top_5 = category_totals.most_common(5)

result = {
    "top_5_categories": top_5,
    "total_users_2016": len(users_2016),
    "total_reviews": len(reviews),
    "unique_businesses": len(review_counts)
}

print('__RESULT__:')
print(json.dumps(result))

