reviews = locals()['var_functions.query_db:54']

# Mapping
num_to_business_id = {}
for business in all_businesses:
    num = business['business_id'].split('_')[-1]
    num_to_business_id[num] = business['business_id']

# Extract all categories from description
def extract_all_categories(description):
    if not description:
        return ['General']

    desc = description.lower()
    categories = []

    patterns = [
        (r'range of services in ([^.]+)', 1),
        (r'including ([^.]+)', 1),
        (r'seeking ([^.]+)', 1),
        (r'for ([^.]+?)(?:\.|, making it a)', 1),
        (r'offers a diverse selection of ([^.]+)', 1),
        (r'offers a wide range of ([^.]+)', 1),
        (r'offers a range of ([^.]+)', 1),
        (r'offers ([^.]+?) services', 1),
        (r'destination for ([^.]+)', 1)
    ]

    for pattern, group in patterns:
        matches = re.findall(pattern, desc)
        for match in matches:
            if isinstance(match, tuple):
                text = match[0]
            else:
                text = match

            # Split by comma or 'and'
            cats = re.split(r',\s*|\sand\s|\sor\s', text)

            for cat in cats:
                cat = cat.strip()
                cat = re.sub(r'[^a-zA-Z\s&/-]', '', cat)
                cat = re.sub(r'^\s*in\s+', '', cat)
                cat = re.sub(r'^\s*of\s+', '', cat)
                cat = re.sub(r'^\s*for\s+', '', cat)
                cat = re.sub(r'^\s*and\s+', '', cat)
                cat = cat.strip()

                if len(cat) > 2 and cat not in ['making', 'seeking', 'anyone', 'your']:
                    # Standardize category names
                    if 'restaurant' in cat.lower():
                        cat = 'Restaurants'
                    elif cat.lower() in ['food', 'foods']:
                        cat = 'Food'
                    elif 'beauty' in cat.lower() or 'spa' in cat.lower():
                        cat = 'Beauty & Spas'
                    elif 'nail salon' in cat.lower():
                        cat = 'Nail Salons'
                    elif 'hair salon' in cat.lower():
                        cat = 'Hair Salons'
                    elif 'fitness' in cat.lower() or 'gym' in cat.lower() or 'boot camp' in cat.lower():
                        cat = 'Fitness & Instruction'
                    elif 'pet groomer' in cat.lower():
                        cat = 'Pet Groomers'
                    elif 'veterinarian' in cat.lower():
                        cat = 'Veterinarians'
                    elif 'pet' in cat.lower():
                        cat = 'Pet Services'
                    elif 'automotive' in cat.lower() or 'auto' in cat.lower():
                        cat = 'Automotive'
                    elif 'medical' in cat.lower() or 'doctor' in cat.lower() or 'dentist' in cat.lower():
                        cat = 'Health & Medical'
                    elif 'vietnamese' in cat.lower():
                        cat = 'Vietnamese Restaurants'
                    elif 'education' in cat.lower() or 'school' in cat.lower():
                        cat = 'Education'
                    elif 'chinese' in cat.lower():
                        cat = 'Chinese Restaurants'
                    elif 'grocery' in cat.lower():
                        cat = 'Grocery'
                    elif 'shopping' in cat.lower():
                        cat = 'Shopping'
                    elif 'mover' in cat.lower():
                        cat = 'Movers'
                    elif 'hotel' in cat.lower():
                        cat = 'Hotels & Travel'

                    categories.append(cat.title() if cat[0].islower() else cat)

    # Remove duplicates
    seen = set()
    unique = []
    for cat in categories:
        if cat.lower() not in seen and cat:
            seen.add(cat.lower())
            unique.append(cat)

    return unique if unique else ['General']

# Map business_id to categories
business_categories = {}
for business in all_businesses:
    business_id = business['business_id']
    categories = extract_all_categories(business.get('description', ''))
    business_categories[business_id] = categories

# Count reviews per business_ref and then by category
category_totals = Counter()
review_counts = Counter()

for review in reviews:
    business_ref = review.get('business_ref')
    if business_ref:
        review_counts[business_ref] += 1

# Process all reviews
matched_reviews = 0
for business_ref, count in review_counts.items():
    ref_num = business_ref.split('_')[-1]

    if ref_num in num_to_business_id:
        business_id = num_to_business_id[ref_num]
        categories = business_categories[business_id]

        # For each review, count it for ALL categories the business belongs to
        for category in categories:
            category_totals[category] += count

        matched_reviews += count
    else:
        category_totals['Unknown'] += count

# Get top 5
top_5 = category_totals.most_common(5)

stats = {
    "top_5_business_categories": top_5,
    "total_users_registered_2016": len(locals()['var_functions.query_db:66']),
    "total_reviews_from_these_users": len(reviews),
    "unique_businesses_reviewed": len(review_counts),
    "matched_reviews": matched_reviews
}

print('__RESULT__:')
print(json.dumps(stats, indent=2))

